{
  "success": true,
  "data": {
    "query": "CAISO Business Practice Manual Market Operations Regulation Service participation requirements \"Business Practice Manual\" \"Market Operations\" regulation",
    "num_results": 20,
    "filters_applied": {
      "market": "CAISO",
      "data_type": "report",
      "year_start": 2019,
      "year_end": 2026,
